import React, { useState, useEffect, useRef } from 'react';
import CourseCard from '../components/CourseCard';
import config, { getAllCourses } from '../config/config';
import { getRecentMaterials } from '../services/api';
import './Home.css';  
import { 
  getFeaturedCourses, 
  getStats, 
  checkHealth,
  addSampleCourses 
} from '../services/api';
import { useNavigate } from 'react-router-dom';

const Home = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [backendCourses, setBackendCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [backendStatus, setBackendStatus] = useState('checking');
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);
  
  const [stats, setStats] = useState([
    { title: 'Total Notes', value: 'Loading...', icon: '📄', key: 'notes' },
    { title: 'PYQs', value: 'Loading...', icon: '📝', key: 'pyqs' },
    { title: 'Courses', value: 'Loading...', icon: '🎓', key: 'courses' },
    { title: 'Downloads', value: 'Loading...', icon: '⬇️', key: 'downloads' },
  ]);
  const [showAddCoursesBtn, setShowAddCoursesBtn] = useState(false);
  
  const [latestMaterials, setLatestMaterials] = useState([]);
  const [materialsLoading, setMaterialsLoading] = useState(true);
  const [materialsError, setMaterialsError] = useState('');
  
  const [activeTab, setActiveTab] = useState('all');
  const [hoveredCard, setHoveredCard] = useState(null);
  const [searchSuggestions, setSearchSuggestions] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [animatedStats, setAnimatedStats] = useState([0, 0, 0, 0]);
  
  const searchRef = useRef(null);
  const statsRef = useRef(null);
  const navigate = useNavigate();
  
  const staticCourses = getAllCourses();

  // Intersection Observer for scroll animations
  useEffect(() => {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.classList.add('revealed');
          
          // Animate stats when they come into view
          if (entry.target.classList.contains('stats-section')) {
            animateStats();
          }
        }
      });
    }, { threshold: 0.1, rootMargin: '50px' });

    document.querySelectorAll('.scroll-reveal').forEach(el => {
      observer.observe(el);
    });

    return () => observer.disconnect();
  }, []);

  // Animate stats numbers
  const animateStats = () => {
    const targetValues = stats.map(s => parseInt(s.value) || 0);
    const duration = 2000;
    const steps = 60;
    const stepTime = duration / steps;
    let currentStep = 0;

    const interval = setInterval(() => {
      currentStep++;
      const progress = currentStep / steps;
      
      const newValues = targetValues.map(target => 
        Math.min(Math.floor(target * progress), target)
      );
      
      setAnimatedStats(newValues);

      if (currentStep >= steps) {
        clearInterval(interval);
      }
    }, stepTime);
  };

  useEffect(() => {
    const handleResize = () => {
      setWindowWidth(window.innerWidth);
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    checkBackend();
    fetchData();
    fetchLatestMaterials();
  }, []);

  // Click outside to close suggestions
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (searchRef.current && !searchRef.current.contains(event.target)) {
        setShowSuggestions(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Search suggestions
  useEffect(() => {
    if (searchQuery.length > 1) {
      const allCourses = [...(backendCourses.length ? backendCourses : staticCourses)];
      const filtered = allCourses
        .filter(course => 
          course.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
          course.branch?.toLowerCase().includes(searchQuery.toLowerCase())
        )
        .slice(0, 5);
      setSearchSuggestions(filtered);
      setShowSuggestions(true);
    } else {
      setSearchSuggestions([]);
      setShowSuggestions(false);
    }
  }, [searchQuery, backendCourses]);

  const fetchLatestMaterials = async () => {
    try {
      setMaterialsLoading(true);
      setMaterialsError('');
      
      console.log('Fetching materials from: http://localhost:5000/api/materials');
      
      const response = await fetch('http://localhost:5000/api/materials');
      const data = await response.json();
      
      console.log('Materials API Response:', data);
      
      if (data.success) {
        const transformedMaterials = data.materials.map(m => ({
          ...m,
          course_name: m.course || m.course_name || 'Unknown',
          display_course: m.course || m.course_name || 'Unknown'
        }));
        
        setLatestMaterials(transformedMaterials.slice(0, 6));
      } else {
        setMaterialsError(data.error || 'Failed to fetch materials');
      }
    } catch (error) {
      console.error('Materials fetch error:', error);
      setMaterialsError('Connection failed. Check if backend is running on port 5000');
    } finally {
      setMaterialsLoading(false);
    }
  };

  const handleMaterialClick = async (material) => {
    console.log('📥 Downloading material:', material.id);
    
    try {
      const token = localStorage.getItem('study_portal_token');
      
      if (!token) {
        const shouldLogin = window.confirm('Please login first to download materials. Go to login page?');
        if (shouldLogin) {
          navigate('/login');
        }
        return;
      }
      
      const downloadBtn = document.getElementById(`download-${material.id}`);
      if (downloadBtn) {
        downloadBtn.textContent = '⏳ Downloading...';
        downloadBtn.disabled = true;
        downloadBtn.classList.add('downloading');
      }
      
      const downloadUrl = `http://localhost:5000/api/notes/${material.id}/download`;
      console.log('🔗 Download URL:', downloadUrl);
      
      const response = await fetch(downloadUrl, {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        }
      });
      
      console.log('📊 Response status:', response.status);
      
      if (!response.ok) {
        if (response.status === 401) {
          throw new Error('Session expired. Please login again.');
        } else if (response.status === 404) {
          throw new Error('File not found on server');
        } else {
          throw new Error(`Download failed (${response.status})`);
        }
      }
      
      const blob = await response.blob();
      console.log('📦 Blob size:', blob.size, 'type:', blob.type);
      
      const contentDisposition = response.headers.get('Content-Disposition');
      let filename = material.file_name || `${material.title}.pdf`;
      
      if (contentDisposition) {
        const match = contentDisposition.match(/filename[^;=\n]*=((['"]).*?\2|[^;\n]*)/);
        if (match && match[1]) {
          filename = match[1].replace(/['"]/g, '');
        }
      }
      
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
      
      // Show success message
      const toast = document.createElement('div');
      toast.className = 'toast-message success';
      toast.textContent = '✅ Download started!';
      document.body.appendChild(toast);
      setTimeout(() => toast.remove(), 3000);
      
    } catch (error) {
      console.error('❌ Download error:', error);
      
      let errorMessage = '';
      if (error.message.includes('401')) {
        errorMessage = '⚠️ Session expired. Please login again.';
        localStorage.removeItem('study_portal_token');
        navigate('/login');
      } else if (error.message.includes('404')) {
        errorMessage = '❌ File not found on server. It may have been deleted.';
      } else {
        errorMessage = `❌ Download failed: ${error.message}`;
      }
      
      // Show error toast
      const toast = document.createElement('div');
      toast.className = 'toast-message error';
      toast.textContent = errorMessage;
      document.body.appendChild(toast);
      setTimeout(() => toast.remove(), 3000);
    } finally {
      const downloadBtn = document.getElementById(`download-${material.id}`);
      if (downloadBtn) {
        downloadBtn.textContent = 'Download';
        downloadBtn.disabled = false;
        downloadBtn.classList.remove('downloading');
      }
    }
  };

  const checkBackend = async () => {
    try {
      const health = await checkHealth();
      setBackendStatus('connected');
      console.log('✅ Backend connected:', health);
      
      if (health.course_count === 0) {
        setShowAddCoursesBtn(true);
      }
    } catch (error) {
      setBackendStatus('disconnected');
      console.error('❌ Backend connection failed:', error);
    }
  };

  const handleAddSampleCourses = async () => {
    try {
      setLoading(true);
      const result = await addSampleCourses();
      
      // Show success toast
      const toast = document.createElement('div');
      toast.className = 'toast-message success';
      toast.textContent = `✅ ${result.message}`;
      document.body.appendChild(toast);
      setTimeout(() => toast.remove(), 3000);
      
      setShowAddCoursesBtn(false);
      fetchData();
    } catch (error) {
      // Show error toast
      const toast = document.createElement('div');
      toast.className = 'toast-message error';
      toast.textContent = '❌ Failed to add sample courses';
      document.body.appendChild(toast);
      setTimeout(() => toast.remove(), 3000);
      
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const fetchData = async () => {
    try {
      const coursesData = await getFeaturedCourses(6);
      
      const transformedCourses = coursesData.courses.map(course => ({
        id: course.id,
        name: course.name,
        branch: course.branch || 'General',
        semester: course.semester || 'All',
        code: course.code || 'GEN',
        notes: course.notes || 0,
        pyqs: course.pyqs || 0,
        description: course.description || 'Study materials',
        created_at: course.created_at,
        icon: course.icon || '📚',
        color: course.color || '#6366f1'
      }));
      
      setBackendCourses(transformedCourses);
      
      const statsData = await getStats();
      setStats([
        { 
          title: 'Total Notes', 
          value: `${statsData.totalNotes || config.STATS_DEFAULTS.totalNotes}+`, 
          icon: '📄',
          key: 'notes'
        },
        { 
          title: 'PYQs', 
          value: `${statsData.totalPYQs || config.STATS_DEFAULTS.totalPYQs}+`, 
          icon: '📝',
          key: 'pyqs'
        },
        { 
          title: 'Courses', 
          value: `${statsData.totalCourses || config.STATS_DEFAULTS.totalCourses}+`, 
          icon: '🎓',
          key: 'courses'
        },
        { 
          title: 'Downloads', 
          value: `${statsData.totalDownloads || config.STATS_DEFAULTS.totalDownloads}+`, 
          icon: '⬇️',
          key: 'downloads'
        },
      ]);
      
    } catch (error) {
      console.error('Error fetching data:', error);
      
      setBackendCourses([]);
      
      setStats([
        { 
          title: 'Total Notes', 
          value: `${config.STATS_DEFAULTS.totalNotes}+`, 
          icon: '📄',
          key: 'notes'
        },
        { 
          title: 'PYQs', 
          value: `${config.STATS_DEFAULTS.totalPYQs}+`, 
          icon: '📝',
          key: 'pyqs'
        },
        { 
          title: 'Courses', 
          value: `${config.STATS_DEFAULTS.totalCourses}+`, 
          icon: '🎓',
          key: 'courses'
        },
        { 
          title: 'Downloads', 
          value: `${config.STATS_DEFAULTS.totalDownloads}+`, 
          icon: '⬇️',
          key: 'downloads'
        },
      ]);
      
      setBackendStatus('disconnected');
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = async () => {
    if (searchQuery.trim()) {
      navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
      setSearchQuery('');
      setShowSuggestions(false);
    }
  };

  const handleSuggestionClick = (course) => {
    navigate(`/course/${course.id}`);
    setSearchQuery('');
    setShowSuggestions(false);
  };

  const handleCourseClick = (courseId) => {
    navigate(`/course/${courseId}`);
  };

  const displayCourses = backendStatus === 'connected' && backendCourses.length > 0 
    ? backendCourses 
    : staticCourses.map(course => ({
        id: course.id,
        name: course.name,
        branch: course.branches?.[0] || 'General',
        semester: 'All',
        code: course.name.substring(0, 4).toUpperCase(),
        notes: config.STATS_DEFAULTS.totalNotes / 5,
        pyqs: config.STATS_DEFAULTS.totalPYQs / 5,
        description: course.description,
        icon: course.icon || '📚',
        color: course.color || '#6366f1',
        duration: course.duration
      }));

  // Filter materials based on active tab
  const filteredMaterials = activeTab === 'all' 
    ? latestMaterials 
    : latestMaterials.filter(m => (m.material_type || m.note_type) === activeTab);

  const features = [
    { title: 'Updated Content', desc: 'Regularly updated materials', icon: '✅' },
    { title: 'Easy Search', desc: 'Find materials quickly', icon: '🔍' },
    { title: 'Mobile Friendly', desc: 'Access on any device', icon: '📱' },
    { title: 'Free Forever', desc: 'All resources free', icon: '🆓' },
  ];

  const getMaterialTypeColor = (type) => {
    switch (type?.toLowerCase()) {
      case 'notes': return { background: '#dbeafe', color: '#1d4ed8' };
      case 'pyq': return { background: '#fef3c7', color: '#d97706' };
      case 'syllabus': return { background: '#dcfce7', color: '#15803d' };
      case 'imp_questions': return { background: '#f3e8ff', color: '#7c3aed' };
      default: return { background: '#f1f5f9', color: '#64748b' };
    }
  };

  const tabs = [
    { id: 'all', label: 'All', icon: '📋' },
    { id: 'notes', label: 'Notes', icon: '📄' },
    { id: 'pyq', label: 'PYQs', icon: '📝' },
    { id: 'syllabus', label: 'Syllabus', icon: '📚' },
    { id: 'imp_questions', label: 'Imp Qs', icon: '❓' },
  ];

  return (
    <div className="home-page">
      {/* Hero Section */}
      <section className="hero-section">
        <div className="hero-particles"></div>
        
        <div className={`status-badge ${backendStatus === 'connected' ? 'connected' : 'disconnected'} glow-on-hover`}>
          <span className="status-indicator"></span>
          {backendStatus === 'connected' ? 'Connected' : 'Disconnected'}
          <span className="status-url">
            {backendStatus === 'connected' ? 'localhost:5000' : 'Offline'}
          </span>
        </div>
        
        <h1 className="hero-title">
          Welcome to <span className="gradient-text">{config.APP_NAME}</span>
        </h1>
        <p className="hero-subtitle">
          Your one-stop destination for notes, PYQs, syllabus and study materials
        </p>
        
        <div className="search-wrapper" ref={searchRef}>
          <div className="search-container">
            <input
              type="text"
              className="search-input"
              placeholder="Search courses, notes, PYQs..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSearch()}
              onFocus={() => searchQuery.length > 1 && setShowSuggestions(true)}
            />
            <button 
              className="search-button"
              onClick={handleSearch}
            >
              <span className="search-icon">🔍</span>
              <span className="search-text">Search</span>
            </button>
          </div>

          {/* Search Suggestions */}
          {showSuggestions && searchSuggestions.length > 0 && (
            <div className="search-suggestions">
              {searchSuggestions.map(course => (
                <div
                  key={course.id}
                  className="suggestion-item"
                  onClick={() => handleSuggestionClick(course)}
                >
                  <span className="suggestion-icon">{course.icon || '📚'}</span>
                  <div className="suggestion-info">
                    <span className="suggestion-title">{course.name}</span>
                    <span className="suggestion-subtitle">{course.branch}</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {showAddCoursesBtn && backendStatus === 'connected' && (
          <button 
            className="add-courses-btn"
            onClick={handleAddSampleCourses}
            disabled={loading}
          >
            {loading ? (
              <>
                <span className="spinner-small"></span>
                Adding...
              </>
            ) : (
              <>
                <span>➕</span>
                Add Sample Courses
              </>
            )}
          </button>
        )}

        <div className="hero-stats-mini">
          <div className="mini-stat">
            <span className="mini-stat-icon">📚</span>
            <span className="mini-stat-value">{displayCourses.length}</span>
            <span className="mini-stat-label">Courses</span>
          </div>
          <div className="mini-stat">
            <span className="mini-stat-icon">📄</span>
            <span className="mini-stat-value">{stats[0].value}</span>
            <span className="mini-stat-label">Notes</span>
          </div>
          <div className="mini-stat">
            <span className="mini-stat-icon">👥</span>
            <span className="mini-stat-value">10k+</span>
            <span className="mini-stat-label">Students</span>
          </div>
        </div>
      </section>

      {/* Stats Section */}
      <section className="stats-section scroll-reveal" ref={statsRef}>
        <div className="stats-grid">
          {stats.map((stat, index) => (
            <div key={index} className="stat-card">
              <div className="stat-icon">{stat.icon}</div>
              <h3 className="stat-number">
                {animatedStats[index] || stat.value}
              </h3>
              <p className="stat-label">{stat.title}</p>
              <div className="stat-progress">
                <div className="progress-bar" style={{ width: '75%' }}></div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Featured Courses */}
      <section className="courses-section scroll-reveal">
        <h2 className="section-title">
          <span className="title-icon">🎓</span>
          Select Your Course
        </h2>
        
        {loading ? (
          <div className="loading-container">
            <div className="loading-spinner"></div>
            <p>Loading courses...</p>
            <p className="loading-sub">Backend Status: <strong className={backendStatus}>{backendStatus}</strong></p>
          </div>
        ) : displayCourses.length === 0 && backendStatus === 'connected' ? (
          <div className="error-container">
            <div className="error-icon">📭</div>
            <h3 className="error-message">No courses found in database!</h3>
            <p>Click the "Add Sample Courses" button above to populate the database.</p>
            <button 
              className="error-retry-btn"
              onClick={handleAddSampleCourses}
              disabled={loading}
            >
              {loading ? 'Adding...' : '➕ Add Sample Courses'}
            </button>
          </div>
        ) : (
          <>
            <div className="courses-grid">
              {displayCourses.map(course => (
                <div 
                  key={course.id} 
                  className={`course-item ${hoveredCard === course.id ? 'hovered' : ''}`}
                  onClick={() => handleCourseClick(course.id)}
                  onMouseEnter={() => setHoveredCard(course.id)}
                  onMouseLeave={() => setHoveredCard(null)}
                >
                  <CourseCard 
                    course={{
                      ...course,
                      onCourseClick: () => handleCourseClick(course.id)
                    }}
                  />
                </div>
              ))}
            </div>
            
            <div className="view-all">
              <p className="view-all-text">
                Click on any course card to select and view years
              </p>
              <button 
                className="view-all-btn"
                onClick={() => navigate('/courses')}
              >
                Browse All Courses
                <span className="btn-icon">→</span>
              </button>
            </div>
          </>
        )}
      </section>

      {/* Latest Materials Section */}
      <section className="materials-section scroll-reveal">
        <h2 className="section-title">
          <span className="title-icon">📚</span>
          Latest Study Materials
        </h2>

        {/* Material Tabs */}
        {!materialsLoading && !materialsError && latestMaterials.length > 0 && (
          <div className="materials-tabs">
            {tabs.map(tab => (
              <button
                key={tab.id}
                className={`tab-btn ${activeTab === tab.id ? 'active' : ''}`}
                onClick={() => setActiveTab(tab.id)}
              >
                <span className="tab-icon">{tab.icon}</span>
                <span className="tab-label">{tab.label}</span>
              </button>
            ))}
          </div>
        )}
        
        {materialsLoading ? (
          <div className="loading-container">
            <div className="loading-spinner"></div>
            <p>Loading latest materials from backend...</p>
          </div>
        ) : materialsError ? (
          <div className="error-container">
            <div className="error-icon">❌</div>
            <h3 className="error-message">Failed to load materials</h3>
            <p>{materialsError}</p>
            <p className="error-note">
              Make sure backend is running: <code>python app.py</code>
            </p>
          </div>
        ) : latestMaterials.length === 0 ? (
          <div className="empty-materials">
            <div className="empty-icon">📭</div>
            <h3>No materials found</h3>
            <p>Upload some materials to see them here</p>
          </div>
        ) : (
          <>
            <div className="materials-grid">
              {filteredMaterials.map((material) => {
                const typeColor = getMaterialTypeColor(material.material_type || material.note_type);
                
                return (
                  <div 
                    key={material.id} 
                    className="material-card"
                    onMouseEnter={() => setHoveredCard(material.id)}
                    onMouseLeave={() => setHoveredCard(null)}
                  >
                    <div className="material-card-header">
                      <div 
                        className="material-type-badge"
                        style={{
                          background: typeColor.background,
                          color: typeColor.color
                        }}
                      >
                        {(material.material_type || material.note_type || 'notes').toUpperCase()}
                      </div>
                      {material.isNew && <span className="new-badge">NEW</span>}
                    </div>
                    
                    <h4 className="material-title">
                      {material.title}
                    </h4>
                    
                    <div className="material-meta-info">
                      <p className="material-meta">
                        <span className="meta-icon">📚</span>
                        <strong>Course:</strong> {material.course_name || 'N/A'}
                      </p>
                      
                      <p className="material-meta">
                        <span className="meta-icon">👤</span>
                        <strong>Uploaded by:</strong> {material.user_name || 'Unknown'}
                      </p>
                      
                      <p className="material-meta">
                        <span className="meta-icon">📅</span>
                        <strong>Date:</strong> {new Date(material.uploaded_at).toLocaleDateString()}
                      </p>
                    </div>
                    
                    <div className="material-footer">
                      <div className="material-stats">
                        <span title="Views">👁️ {material.views || 0}</span>
                        <span title="Downloads">⬇️ {material.downloads || 0}</span>
                      </div>
                      
                      <button 
                        id={`download-${material.id}`}
                        className="material-download-btn"
                        onClick={(e) => {
                          e.stopPropagation();
                          handleMaterialClick(material);
                        }}
                      >
                        <span className="btn-text">Download</span>
                        <span className="btn-icon">⬇️</span>
                      </button>
                    </div>

                    {/* Progress bar for downloads */}
                    <div className="material-progress">
                      <div 
                        className="progress-fill"
                        style={{ width: `${Math.min((material.downloads || 0) / 10, 100)}%` }}
                      ></div>
                    </div>
                  </div>
                );
              })}
            </div>
            
            <div className="view-all">
              <button 
                className="view-all-btn"
                onClick={() => navigate('/materials')}
              >
                View All Materials
                <span className="btn-icon">→</span>
              </button>
            </div>
          </>
        )}
      </section>

      {/* Features Section */}
      <section className="features-section scroll-reveal">
        <h2 className="section-title">
          <span className="title-icon">✨</span>
          Why Choose {config.APP_NAME}?
        </h2>
        <div className="features-grid">
          {features.map((feature, index) => (
            <div key={index} className="feature-card">
              <div className="feature-icon-wrapper">
                <div className="feature-icon">{feature.icon}</div>
              </div>
              <h3 className="feature-title">{feature.title}</h3>
              <p className="feature-desc">{feature.desc}</p>
              <div className="feature-shine"></div>
            </div>
          ))}
        </div>
      </section>

      {/* Backend Info */}
      <div className="backend-info">
        <div className="info-grid">
          <div className="info-item">
            <span className="info-label">Backend Status:</span>
            <span className={`info-value status-${backendStatus}`}>
              {backendStatus === 'connected' ? '✅ Live' : '❌ Offline'}
            </span>
          </div>
          <div className="info-item">
            <span className="info-label">Courses Loaded:</span>
            <span className="info-value">{displayCourses.length}</span>
          </div>
          <div className="info-item">
            <span className="info-label">Latest Materials:</span>
            <span className="info-value">{latestMaterials.length}</span>
          </div>
          <div className="info-item">
            <span className="info-label">Mode:</span>
            <span className="info-value">
              {backendStatus === 'connected' ? 'Live API' : 'Static Demo'}
            </span>
          </div>
        </div>
        <p className="backend-note">
          {backendStatus === 'connected' 
            ? '🎉 Frontend-Backend Connection Successful!' 
            : '⚠️ Using static demo data. Start backend for live features.'}
        </p>
      </div>

      {/* Floating Action Button for mobile */}
      {windowWidth <= 768 && (
        <button 
          className="fab-button"
          onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
        >
          ↑
        </button>
      )}
    </div>
  );
};

export default Home;
